{
  "title": "Primary School Exam",
   "description": "A comprehensive exam for primary school students",
   "timeLimit": 120,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "title": "COMPREHENSION (20 Marks)",
           "description": "Read the passage carefully and answer the questions.",
           "passage": "My name is Keza. I study at Sunrise Primary School. Every morning, I walk to school with my brother. It takes us twenty minutes to reach school. My favourite subject is English because I enjoy reading stories. At school, there is a big library and many classrooms. After lessons, I play football with my friends before going home.",
           "questions": [
               {
                   "text": "What is the name of the school?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Sunrise Primary School"
               },
               {
                   "text": "Who does Keza walk to school with?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Her brother"
               },
               {
                   "text": "How long does it take Keza to reach school?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Twenty minutes"
               },
               {
                   "text": "What is Keza’s favourite subject?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "English"
               },
               {
                   "text": "Why does Keza like the subject?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "She enjoys reading stories"
               },
               {
                   "text": "Mention two things found at Keza’s school.",
                   "type": "short-answer",
                   "points": 4,
                   "correctAnswer": "Library and classrooms"
               },
               {
                   "text": "What does Keza do after lessons?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "She plays football"
               },
               {
                   "text": "Do you enjoy playing with friends after school? Why?",
                   "type": "open-ended",
                   "points": 4,
                   "correctAnswer": "Learner’s opinion"
               }
           ]
       },
       {
           "name": "B",
           "title": "VOCABULARY (15 Marks)",
           "description": "Match the words with their meanings and fill in the blanks.",
           "subsections": [
               {
                   "name": "A",
                   "title": "Match the words with their meanings. (5 marks)",
                   "instructions": "Match the words with their meanings.",
                   "questions": [
                       {
                           "text": "1. Doctor",
                           "type": "matching",
                           "points": 1,
                           "options": [
                               {"text": "a. A place where children learn", "isCorrect": false},
                               {"text": "b. A person who treats sick people", "isCorrect": true},
                               {"text": "c. A place where people buy and sell things", "isCorrect": false},
                               {"text": "d. A place with books", "isCorrect": false},
                               {"text": "e. A person who grows crops", "isCorrect": false}
                           ],
                           "correctAnswer": "b"
                       },
                       {
                           "text": "2. School",
                           "type": "matching",
                           "points": 1,
                           "options": [
                               {"text": "a. A place where children learn", "isCorrect": true},
                               {"text": "b. A person who treats sick people", "isCorrect": false},
                               {"text": "c. A place where people buy and sell things", "isCorrect": false},
                               {"text": "d. A place with books", "isCorrect": false},
                               {"text": "e. A person who grows crops", "isCorrect": false}
                           ],
                           "correctAnswer": "a"
                       },
                       {
                           "text": "3. Market",
                           "type": "matching",
                           "points": 1,
                           "options": [
                               {"text": "a. A place where children learn", "isCorrect": false},
                               {"text": "b. A person who treats sick people", "isCorrect": false},
                               {"text": "c. A place where people buy and sell things", "isCorrect": true},
                               {"text": "d. A place with books", "isCorrect": false},
                               {"text": "e. A person who grows crops", "isCorrect": false}
                           ],
                           "correctAnswer": "c"
                       },
                       {
                           "text": "4. Library",
                           "type": "matching",
                           "points": 1,
                           "options": [
                               {"text": "a. A place where children learn", "isCorrect": false},
                               {"text": "b. A person who treats sick people", "isCorrect": false},
                               {"text": "c. A place where people buy and sell things", "isCorrect": false},
                               {"text": "d. A place with books", "isCorrect": true},
                               {"text": "e. A person who grows crops", "isCorrect": false}
                           ],
                           "correctAnswer": "d"
                       },
                       {
                           "text": "5. Farmer",
                           "type": "matching",
                           "points": 1,
                           "options": [
                               {"text": "a. A place where children learn", "isCorrect": false},
                               {"text": "b. A person who treats sick people", "isCorrect": false},
                               {"text": "c. A place where people buy and sell things", "isCorrect": false},
                               {"text": "d. A place with books", "isCorrect": false},
                               {"text": "e. A person who grows crops", "isCorrect": true}
                           ],
                           "correctAnswer": "e"
                       }
                   ]
               },
               {
                   "name": "B",
                   "title": "Fill in the blanks using the correct words from the box. (10 marks)",
                   "wordBank": ["sunny", "library", "singing", "playground", "rainy"],
                   "instructions": "Fill in the blanks using the correct words from the box.",
                   "questions": [
                       {
                           "text": "We read books in the ____________.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "library"
                       },
                       {
                           "text": "Children play football in the ____________.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "playground"
                       },
                       {
                           "text": "It is ____________ today. I can see the sun.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "sunny"
                       },
                       {
                           "text": "The girls are ____________ songs.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "singing"
                       },
                       {
                           "text": "We carry umbrellas when it is ____________.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "rainy"
                       }
                   ]
               }
           ]
       },
       {
           "name": "C",
           "title": "GRAMMAR (25 Marks)",
           "description": "Write the negative form of the sentences, questions using the words given, and fill in the blanks with the correct form of the verbs.",
           "subsections": [
               {
                   "name": "A",
                   "title": "Write the negative form of the following sentences. (5 marks)",
                   "instructions": "Write the negative form of the sentences.",
                   "questions": [
                       {
                           "text": "She likes English.",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "She does not like English."
                       },
                       {
                           "text": "They play football every day.",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "They do not play football every day."
                       },
                       {
                           "text": "He walks to school.",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "He does not walk to school."
                       },
                       {
                           "text": "We study Mathematics.",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "We do not study Mathematics."
                       },
                       {
                           "text": "Aline enjoys dancing.",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Aline does not enjoy dancing."
                       }
                   ]
               },
               {
                   "name": "B",
                   "title": "Write questions using the words given. (5 marks)",
                   "instructions": "Write questions using the words given.",
                   "questions": [
                       {
                           "text": "you / like / English",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Do you like English?"
                       },
                       {
                           "text": "she / go / to school",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Does she go to school?"
                       },
                       {
                           "text": "they / play / football",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Do they play football?"
                       },
                       {
                           "text": "he / enjoy / reading",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Does he enjoy reading?"
                       },
                       {
                           "text": "we / study / Science",
                           "type": "short-answer",
                           "points": 1,
                           "correctAnswer": "Do we study Science?"
                       }
                   ]
               },
               {
                   "name": "C",
                   "title": "Fill in the blanks with the correct form of the verbs in brackets. (10 marks)",
                   "instructions": "Fill in the blanks with the correct form of the verbs in brackets.",
                   "questions": [
                       {
                           "text": "She ____________ (walk) to school every day.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "walks"
                       },
                       {
                           "text": "We ____________ (study) English on Monday.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "study"
                       },
                       {
                           "text": "He ____________ (like) football.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "likes"
                       },
                       {
                           "text": "They ____________ (play) in the playground.",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "play"
                       },
                       {
                           "text": "Does she ____________ (teach) English?",
                           "type": "fill-in-blank",
                           "points": 2,
                           "correctAnswer": "teach"
                       }
                   ]
               },
               {
                   "name": "D",
                   "title": "Choose the correct answer. (5 marks)",
                   "instructions": "Choose the correct answer.",
                   "questions": [
                       {
                           "text": "There ____ many books in the library.",
                           "type": "multiple-choice",
                           "points": 1,
                           "options": [
                               {"text": "is", "isCorrect": false},
                               {"text": "are", "isCorrect": true},
                               {"text": "am", "isCorrect": false}
                           ],
                           "correctAnswer": "are"
                       },
                       {
                           "text": "The school is ____ the market.",
                           "type": "multiple-choice",
                           "points": 1,
                           "options": [
                               {"text": "behind", "isCorrect": true},
                               {"text": "eat", "isCorrect": false},
                               {"text": "run", "isCorrect": false}
                           ],
                           "correctAnswer": "behind"
                       },
                       {
                           "text": "It ____ rainy yesterday.",
                           "type": "multiple-choice",
                           "points": 1,
                           "options": [
                               {"text": "is", "isCorrect": false},
                               {"text": "was", "isCorrect": true},
                               {"text": "are", "isCorrect": false}
                           ],
                           "correctAnswer": "was"
                       },
                       {
                           "text": "She is taller ____ Aline.",
                           "type": "multiple-choice",
                           "points": 1,
                           "options": [
                               {"text": "than", "isCorrect": true},
                               {"text": "then", "isCorrect": false},
                               {"text": "that", "isCorrect": false}
                           ],
                           "correctAnswer": "than"
                       },
                       {
                           "text": "I am going to ____ my grandmother.",
                           "type": "multiple-choice",
                           "points": 1,
                           "options": [
                               {"text": "visit", "isCorrect": true},
                               {"text": "visiting", "isCorrect": false},
                               {"text": "visits", "isCorrect": false}
                           ],
                           "correctAnswer": "visit"
                       }
                   ]
               }
           ]
       },
       {
           "name": "D",
           "title": "WEATHER (10 Marks)",
           "description": "Mention four types of weather, what people wear when it is cold, and what the weather was like yesterday.",
           "questions": [
               {
                   "text": "Mention four types of weather.",
                   "type": "short-answer",
                   "points": 4,
                   "correctAnswer": "Sunny, rainy, cloudy, windy"
               },
               {
                   "text": "What do people wear when it is cold?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Coats, hats, gloves"
               },
               {
                   "text": "What was the weather like yesterday? Write one sentence.",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "The weather was sunny yesterday."
               },
               {
                   "text": "Why is weather important?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "Weather is important because it affects our daily activities and plans."
               }
           ]
       },
       {
           "name": "E",
           "title": "WRITING (20 Marks)",
           "description": "Write five sentences about your school and what you did last weekend.",
           "questions": [
               {
                   "text": "Write five sentences about your school.",
                   "type": "short-answer",
                   "points": 10,
                   "correctAnswer": "There is a big library in my school. There are many classrooms in my school. My school is next to the park. My school is behind the market. I like my school."
               },
               {
                   "text": "Write five sentences about what you did last weekend.",
                   "type": "short-answer",
                   "points": 10,
                   "correctAnswer": "I visited my grandmother last weekend. I played football with my friends. I went to the park with my family. I watched a movie on Sunday. I did my homework on Saturday."
               }
           ]
       },
       {
           "name": "F",
           "title": "ATTITUDES AND VALUES (10 Marks)",
           "description": "Write two ways you can help keep your school clean, two qualities of a good friend, and why it is important to come to school on time.",
           "questions": [
               {
                   "text": "Write two ways you can help keep your school clean.",
                   "type": "short-answer",
                   "points": 4,
                   "correctAnswer": "I can help keep my school clean by throwing away trash and recycling paper. I can also help by cleaning up after myself in the cafeteria."
               },
               {
                   "text": "Write two qualities of a good friend.",
                   "type": "short-answer",
                   "points": 4,
                   "correctAnswer": "A good friend is kind and loyal. A good friend is also honest and trustworthy."
               },
               {
                   "text": "Why is it important to come to school on time?",
                   "type": "short-answer",
                   "points": 2,
                   "correctAnswer": "It is important to come to school on time because it shows respect for the teachers and other students. It also helps me to stay focused and learn better."
               }
           ]
       }
   ]
}
